import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { db } from '../firebase';
import { collection, addDoc } from 'firebase/firestore';
import { ArrowLeft, MapPin, Phone, Building2, CreditCard, Wallet, Truck, CheckCircle2, Loader2, Info } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const Checkout = () => {
    const { cart, cartTotal, clearCart } = useCart();
    const { currentUser, userData, saveAddress } = useAuth();
    const navigate = useNavigate();

    const addresses = userData?.addresses || [];

    // Select default address if available, otherwise just pick the first one, else null
    const [selectedAddressId, setSelectedAddressId] = useState(
        addresses.find(a => a.isDefault)?.id || addresses[0]?.id || null
    );

    const [isAddingNew, setIsAddingNew] = useState(addresses.length === 0);
    const [form, setForm] = useState({
        label: 'Home',
        address: '',
        city: '',
        pincode: '',
        phone: userData?.phone || ''
    });

    // When addresses array updates from Firebase, auto-select if needed
    useEffect(() => {
        if (addresses.length > 0 && !selectedAddressId) {
            setSelectedAddressId(addresses.find(a => a.isDefault)?.id || addresses[0]?.id);
            setIsAddingNew(false);
        } else if (addresses.length === 0) {
            setIsAddingNew(true);
        }
    }, [addresses, selectedAddressId]);

    const [paymentMethod, setPaymentMethod] = useState('COD');
    const [isPlacingOrder, setIsPlacingOrder] = useState(false);
    const [orderSuccess, setOrderSuccess] = useState(false);

    const handleInputChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    const handlePlaceOrder = async (e) => {
        e.preventDefault();
        if (cart.length === 0) return;

        if (!paymentMethod) {
            alert("Please select a valid payment method.");
            return;
        }

        setIsPlacingOrder(true);

        try {
            const firstPharmacyId = cart[0]?.pharmacyId;
            if (!firstPharmacyId) throw new Error("Invalid cart data: missing pharmacy info.");

            // Use serverTimestamp from Firebase
            const { serverTimestamp } = await import('firebase/firestore');

            let finalAddress;

            if (isAddingNew) {
                // Save new address to profile
                finalAddress = await saveAddress(form);
            } else {
                // Use selected existing address
                finalAddress = addresses.find(a => a.id === selectedAddressId);
                if (!finalAddress) throw new Error("Please select a delivery address.");
            }

            const orderData = {
                customerId: currentUser.uid,
                pharmacyId: firstPharmacyId,
                customerInfo: {
                    name: currentUser.displayName || userData?.name || 'Customer',
                    phone: finalAddress.phone,
                    address: finalAddress.address,
                    city: finalAddress.city,
                    pincode: finalAddress.pincode
                },
                items: cart,
                totalAmount: cartTotal + 2,
                paymentMethod: "COD",
                paymentStatus: "pending",
                orderStatus: "pending",
                createdAt: serverTimestamp()
            };

            const docRef = await addDoc(collection(db, 'orders'), orderData);

            // Clear cart from context
            clearCart();

            setOrderSuccess(true);
            setTimeout(() => {
                navigate(`/order-tracking/${docRef.id}`);
            }, 2000);
        } catch (err) {
            console.error("Order placement failed:", err);
            alert('Failed to place order: ' + err.message);
        } finally {
            setIsPlacingOrder(false);
        }
    };

    if (orderSuccess) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-white">
                <motion.div
                    initial={{ scale: 0.5, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="text-center"
                >
                    <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-8 text-[#2e7d32]">
                        <CheckCircle2 size={60} />
                    </div>
                    <h1 className="text-4xl font-black text-gray-800 mb-4">Order Placed!</h1>
                    <p className="text-gray-500 font-bold mb-8 text-lg">Your medicines are on the way.</p>
                    <div className="flex flex-col items-center gap-2">
                        <Loader2 className="animate-spin text-[#2e7d32]" size={24} />
                        <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">Opening tracking page...</p>
                    </div>
                </motion.div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto px-4 py-10 md:py-16">
            <button
                onClick={() => navigate('/cart')}
                className="flex items-center gap-2 text-[#2e7d32] font-bold mb-10 hover:opacity-70 transition-opacity group"
            >
                <ArrowLeft size={20} className="group-hover:-translate-x-1 transition-transform" />
                Back to Cart
            </button>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                <div className="lg:col-span-2">
                    <h1 className="text-4xl font-black text-gray-800 mb-12">Checkout</h1>

                    <form id="checkout-form" onSubmit={handlePlaceOrder} className="space-y-10">
                        {/* Delivery Section */}
                        <section className="bg-white p-6 md:p-8 rounded-[2.5rem] border border-gray-100 shadow-sm">
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-xl font-black text-gray-800 flex items-center gap-3">
                                    <MapPin size={24} className="text-[#2e7d32]" />
                                    Delivery Address
                                </h2>
                                {!isAddingNew && addresses.length > 0 && (
                                    <button
                                        type="button"
                                        onClick={() => setIsAddingNew(true)}
                                        className="text-sm font-bold text-[#2e7d32] hover:underline"
                                    >
                                        + Add New
                                    </button>
                                )}
                            </div>

                            {/* Address Selector */}
                            {!isAddingNew && addresses.length > 0 && (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {addresses.map(addr => (
                                        <label
                                            key={addr.id}
                                            className={`relative p-5 rounded-3xl border-2 cursor-pointer transition-all ${selectedAddressId === addr.id
                                                ? 'border-[#2e7d32] bg-green-50 shadow-md'
                                                : 'border-gray-100 bg-white hover:border-gray-200'
                                                }`}
                                        >
                                            <input
                                                type="radio"
                                                name="address"
                                                value={addr.id}
                                                checked={selectedAddressId === addr.id}
                                                onChange={() => setSelectedAddressId(addr.id)}
                                                className="hidden"
                                            />
                                            {selectedAddressId === addr.id && (
                                                <div className="absolute top-4 right-4 text-[#2e7d32]">
                                                    <CheckCircle2 size={20} className="fill-[#2e7d32] text-white" />
                                                </div>
                                            )}
                                            <div className="pr-8">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <span className="text-xs font-black bg-gray-200 text-gray-700 px-2 py-0.5 rounded-md uppercase tracking-wide">
                                                        {addr.label}
                                                    </span>
                                                    {addr.isDefault && (
                                                        <span className="text-[10px] font-black bg-[#2e7d32]/10 text-[#2e7d32] px-2 py-0.5 rounded-full uppercase tracking-widest">
                                                            Default
                                                        </span>
                                                    )}
                                                </div>
                                                <p className="text-sm text-gray-600 font-bold leading-relaxed line-clamp-2">{addr.address}</p>
                                                <p className="text-sm text-gray-800 font-bold mt-2">{addr.city} - {addr.pincode}</p>
                                                <p className="text-sm text-gray-500 font-medium mt-1">📞 {addr.phone}</p>
                                            </div>
                                        </label>
                                    ))}
                                </div>
                            )}

                            {/* Add New Form */}
                            {isAddingNew && (
                                <div className="animate-in fade-in slide-in-from-top-4 duration-300">
                                    {addresses.length > 0 && (
                                        <button
                                            type="button"
                                            onClick={() => setIsAddingNew(false)}
                                            className="text-sm font-bold text-gray-500 hover:text-gray-800 mb-6 flex items-center gap-1"
                                        >
                                            <ArrowLeft size={16} /> Back to saved addresses
                                        </button>
                                    )}
                                    <div className="flex gap-3 mb-6">
                                        {['Home', 'Work', 'Other'].map(lbl => (
                                            <button
                                                type="button"
                                                key={lbl}
                                                onClick={() => setForm({ ...form, label: lbl })}
                                                className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all ${form.label === lbl
                                                    ? 'bg-[#2e7d32] text-white shadow-md'
                                                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                                                    }`}
                                            >
                                                {lbl}
                                            </button>
                                        ))}
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div className="md:col-span-2">
                                            <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Full Address</label>
                                            <textarea
                                                name="address"
                                                required={isAddingNew}
                                                value={form.address}
                                                onChange={handleInputChange}
                                                rows="3"
                                                placeholder="Flat/House No, Floor, Building, Street..."
                                                className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#2e7d32]/20 focus:border-[#2e7d32] transition-all"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">City</label>
                                            <input
                                                type="text"
                                                name="city"
                                                required={isAddingNew}
                                                value={form.city}
                                                onChange={handleInputChange}
                                                placeholder="Bhopal"
                                                className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#2e7d32]/20 focus:border-[#2e7d32] transition-all"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Pincode</label>
                                            <input
                                                type="text"
                                                name="pincode"
                                                required={isAddingNew}
                                                value={form.pincode}
                                                onChange={handleInputChange}
                                                placeholder="462001"
                                                className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#2e7d32]/20 focus:border-[#2e7d32] transition-all"
                                            />
                                        </div>
                                        <div className="md:col-span-2">
                                            <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Phone Number</label>
                                            <div className="relative">
                                                <Phone size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400" />
                                                <input
                                                    type="tel"
                                                    name="phone"
                                                    required={isAddingNew}
                                                    value={form.phone}
                                                    onChange={handleInputChange}
                                                    placeholder="10 digit mobile number"
                                                    className="w-full pl-12 pr-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#2e7d32]/20 focus:border-[#2e7d32] transition-all"
                                                />
                                            </div>
                                        </div>
                                    </div>
                                    <div className="mt-4 p-3 bg-blue-50 text-blue-600 rounded-xl text-xs font-bold flex items-center gap-2">
                                        <Info size={16} /> This new address will be securely saved to your Profile for next time!
                                    </div>
                                </div>
                            )}
                        </section>

                        {/* Payment Method Section */}
                        <section className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm">
                            <h2 className="text-xl font-black text-gray-800 mb-8 flex items-center gap-3">
                                <CreditCard size={24} className="text-[#2e7d32]" />
                                Payment Method
                            </h2>
                            <div className="flex flex-col gap-4 max-w-md">
                                <label className="flex items-center gap-4 p-5 rounded-2xl border-2 border-[#2e7d32] bg-green-50 cursor-pointer transition-all hover:shadow-sm">
                                    <input
                                        type="radio"
                                        name="paymentMethod"
                                        value="COD"
                                        checked={paymentMethod === 'COD'}
                                        onChange={(e) => setPaymentMethod(e.target.value)}
                                        className="hidden"
                                    />
                                    <div className="w-6 h-6 rounded-full border-2 border-[#2e7d32] flex items-center justify-center">
                                        <div className="w-3 h-3 bg-[#2e7d32] rounded-full" />
                                    </div>
                                    <div className="flex-grow">
                                        <p className="font-bold text-gray-800">Cash on Delivery</p>
                                        <p className="text-xs text-gray-500 font-medium mt-0.5">Pay when your order arrives</p>
                                    </div>
                                    <Wallet className="text-[#2e7d32]" />
                                </label>

                                <div className="mt-2 flex items-start gap-2 text-gray-400 bg-gray-50 p-3 rounded-xl border border-gray-100">
                                    <Info size={16} className="mt-0.5 flex-shrink-0" />
                                    <p className="text-xs font-bold leading-relaxed">Online Payment temporarily unavailable.</p>
                                </div>
                            </div>
                        </section>
                    </form>
                </div>

                {/* Order Summary Sticky Sidebar */}
                <div className="lg:col-span-1">
                    <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-lg sticky top-24">
                        <h2 className="text-xl font-black text-gray-800 mb-8 flex items-center gap-2">
                            Order Summary
                            <span className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-1 rounded-lg ml-auto">{cart.length} items</span>
                        </h2>

                        <div className="max-h-[300px] overflow-y-auto pr-2 mb-8 space-y-4">
                            {cart.map(item => (
                                <div key={item.medicineId} className="flex justify-between items-center gap-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-gray-50 rounded-lg flex-shrink-0 border border-gray-100 overflow-hidden">
                                            <img src={item.imageURL} alt="" className="w-full h-full object-contain" />
                                        </div>
                                        <div>
                                            <p className="text-sm font-bold text-gray-800 line-clamp-1">{item.name}</p>
                                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{item.quantity} x ₹{item.price}</p>
                                        </div>
                                    </div>
                                    <span className="text-sm font-black text-gray-700">₹{item.price * item.quantity}</span>
                                </div>
                            ))}
                        </div>

                        <div className="space-y-4 pt-6 border-t border-gray-100 mb-8">
                            <div className="flex justify-between text-gray-500 font-medium text-sm">
                                <span>Item Total</span>
                                <span>₹{cartTotal}</span>
                            </div>
                            <div className="flex justify-between text-gray-500 font-medium text-sm">
                                <span>Delivery Fee</span>
                                <span className="text-[#2e7d32] font-black uppercase text-[10px] bg-green-50 px-2 py-0.5 rounded-md">Free</span>
                            </div>
                            <div className="flex justify-between text-gray-500 font-medium text-sm">
                                <span>Handling Charge</span>
                                <span>₹2</span>
                            </div>
                            <div className="flex justify-between items-center pt-4 text-gray-900 font-black text-xl">
                                <span>To Pay</span>
                                <span>₹{cartTotal + 2}</span>
                            </div>
                        </div>

                        {/* Safety Note */}
                        <div className="bg-gray-50 p-4 rounded-2xl flex items-start gap-3 mb-8">
                            <Truck size={18} className="text-blue-500 mt-0.5 shrink-0" />
                            <p className="text-[10px] text-gray-400 font-bold leading-tight">
                                Delivering to you via our verified partners. Your health and safety is our priority.
                            </p>
                        </div>

                        <button
                            form="checkout-form"
                            type="submit"
                            disabled={isPlacingOrder}
                            className="w-full py-5 bg-[#2e7d32] text-white rounded-2xl font-black text-lg shadow-xl shadow-green-900/10 hover:bg-[#1b5e20] transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                        >
                            {isPlacingOrder ? (
                                <Loader2 className="animate-spin" size={24} />
                            ) : (
                                <>
                                    Place Order • ₹{cartTotal + 2}
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Checkout;
